module decoder_3to8 (
	input [1:0] inverted_in,
	input en,
	output [3:0] out);

	assign out = en ? (1 << inverted_in) : 4'b0000;

endmodule

module decoder_3to8 (
	input [2:0] inverted_in,
	input en,
	output [7:0] out);

	wire [3:0] d1_out, d2_out;

	decoder_2to4 d1(.inverted_in(inverted_in[1:0]), .en(en & ~inverted_in[2]), .out(d1_out));
	decoder_2to4 d2(.inverted_in(inverted_in[1:0]), .en(en & inverted_in[2]), .out(d2_out));

	assign out = {d2_out, d1_out};

endmodule
